-- Seed: Référentiel PSSI-ES — 11 domaines, 155 contrôles
-- Source : Instruction présidentielle N° 003/PR du 03 janvier 2017
-- Commission Nationale de Cryptologie — Présidence de la République du Sénégal

INSERT INTO public.frameworks (id, name, slug, description, version, publisher, category)
VALUES (
  '00000000-0000-0000-0000-000000000017',
  'PSSI-ES — Sénégal',
  'pssi-es',
  'Politique de Sécurité des Systèmes d''Information de l''État du Sénégal. Instruction présidentielle N° 003/PR du 03 janvier 2017. Définit les principes, règles et mesures de sécurité applicables à tous les SI des entités étatiques. Structurée en 11 chapitres, 30 objectifs et 155 règles couvrant l''organisation, le personnel, l''acquisition, les actifs, les fournisseurs, la sécurité physique, logique, l''exploitation, le cloud/mobile, les incidents et l''audit.',
  '2017',
  'Commission Nationale de Cryptologie / Présidence de la République du Sénégal',
  'conformite'
)
ON CONFLICT (id) DO NOTHING;

-- ============================================================
-- Domaines (11 chapitres de l'annexe)
-- ============================================================

-- Nettoyage préventif (idempotent)
DELETE FROM public.controls WHERE domain_id IN (
  SELECT id FROM public.domains WHERE framework_id = '00000000-0000-0000-0000-000000000017'
);
DELETE FROM public.domains WHERE framework_id = '00000000-0000-0000-0000-000000000017';

insert into public.domains (id, framework_id, code, name, description, sort_order) values
('00000000-0000-0000-0008-000000000001', '00000000-0000-0000-0000-000000000017', 'ORG', 'Organisation de la sécurité des SI', 'Objectif 1 : Mettre en place une organisation appropriée pour engager, puis contrôler la mise en œuvre et le fonctionnement de la sécurité des systèmes d''information. Structure à 3 niveaux : décisionnel, pilotage, opérationnel.', 1),
('00000000-0000-0000-0008-000000000002', '00000000-0000-0000-0000-000000000017', 'PER', 'Sécurité du personnel', 'Objectifs 2-4 : Sélection, affectation, sensibilisation et formation du personnel à la sécurité des systèmes d''information.', 2),
('00000000-0000-0000-0008-000000000003', '00000000-0000-0000-0000-000000000017', 'ACQ', 'Acquisition et développement des SI', 'Objectif 5 : Intégrer la sécurité durant tout le cycle de vie des systèmes d''information lors de l''acquisition et du développement de nouveaux systèmes.', 3),
('00000000-0000-0000-0008-000000000004', '00000000-0000-0000-0000-000000000017', 'ACT', 'Gestion des actifs', 'Objectif 6 : Les actifs de l''organisme, notamment en matière de système d''information, doivent être identifiés et affectés à des responsables qui doivent en assurer la protection.', 4),
('00000000-0000-0000-0008-000000000005', '00000000-0000-0000-0000-000000000017', 'FRN', 'Relation avec les fournisseurs', 'Objectif 7 : Garantir la protection des actifs de l''organisme accessibles aux fournisseurs.', 5),
('00000000-0000-0000-0008-000000000006', '00000000-0000-0000-0000-000000000017', 'PHY', 'Sécurité physique', 'Objectifs 8-16 : Zones sécurisées, contrôle d''entrée, sécurisation des bureaux, zones de livraison, emplacement et protection des matériels, câblage, maintenance, bureau propre et écran vide.', 6),
('00000000-0000-0000-0008-000000000007', '00000000-0000-0000-0000-000000000017', 'LOG', 'Sécurité logique', 'Objectifs 17-19 : Sécurité des accès (besoin d''en connaître et d''utiliser), sécurité des applicatifs, sécurité des échanges et cryptologie.', 7),
('00000000-0000-0000-0008-000000000008', '00000000-0000-0000-0000-000000000017', 'EXP', 'Sécurité de l''exploitation', 'Objectifs 20-27 : Procédures d''exploitation, gestion des changements, séparation des environnements, protection contre les logiciels malveillants, sauvegarde, journalisation, synchronisation des horloges, installation de logiciels.', 8),
('00000000-0000-0000-0008-000000000009', '00000000-0000-0000-0000-000000000017', 'CLM', 'Cloud, appareils mobiles et télétravail', 'Objectif 28 : Permettre au personnel de mieux appréhender les problèmes de sécurité relatifs au cloud computing, à l''utilisation des appareils mobiles et au télétravail.', 9),
('00000000-0000-0000-0008-000000000010', '00000000-0000-0000-0000-000000000017', 'INC', 'Gestion des incidents', 'Objectif 29 : Établir et mettre en place une procédure de gestion des incidents liés à la sécurité des systèmes d''information incluant la communication des événements et des failles de sécurité.', 10),
('00000000-0000-0000-0008-000000000011', '00000000-0000-0000-0000-000000000017', 'AUD', 'Audit et conformité', 'Objectif 30 : Éviter toute violation des dispositions législatives et réglementaires relatives à la sécurité des systèmes d''information.', 11);

-- ============================================================
-- ORG — Organisation de la sécurité des SI (6 contrôles)
-- Chapitre I — Objectif 1
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000001', 'REG 1-1', 'Formation des AQSSI au Comité de sécurité', 'Les membres du Comité de sécurité agissant en tant qu''AQSSI doivent au préalable subir une sensibilisation et une formation en matière de sécurité des SI, en vue d''accomplir avec efficience les missions qui leur sont confiées.', 'AQSSI = Autorités Qualifiées pour la Sécurité des SI. Niveau pilotage. Mapping ISO 27001 : A.5.2', 1),
('00000000-0000-0000-0008-000000000001', 'REG 1-2', 'Formation confiée aux organismes compétents', 'La sensibilisation et la formation doivent être confiées aux organismes compétents, notamment l''ADIE, le STCC-SSI, l''ARTP ou tout autre organisme public ou privé dont les compétences sont avérées.', 'Organismes de référence : ADIE, STCC-SSI, ARTP. Doivent tenir compte de l''évolution des menaces et des attaques.', 2),
('00000000-0000-0000-0008-000000000001', 'REG 1-3', 'Sensibilisation permanente des ASSI', 'Les Agents de Sécurité des Systèmes d''Information (ASSI) doivent, en permanence, être sensibilisés sur leurs responsabilités et formés au même titre que les AQSSI.', 'Niveau opérationnel. Les ASSI sont chargés de la gestion et du suivi des moyens de sécurité sur le(s) site(s).', 3),
('00000000-0000-0000-0008-000000000001', 'REG 1-4', 'Note d''organisation fixant la répartition des responsabilités', 'Une note d''organisation doit fixer la répartition des responsabilités au sein de l''entité ; cette note doit être proposée par le RSSI et validée par l''autorité de l''entité.', 'Mapping ISO 27001 : A.5.2, A.5.4', 4),
('00000000-0000-0000-0008-000000000001', 'REG 1-5', 'Planification des actions de mise en place de la PSSI-ES', 'Le Responsable de la sécurité des systèmes d''information planifie les actions de mise en place de la PSSI-ES.', 'Le RSSI est le pilote de la mise en œuvre de la PSSI-ES au niveau de l''entité.', 5),
('00000000-0000-0000-0008-000000000001', 'REG 1-6', 'Formalisation et tenue à jour des documents validés', 'Le Responsable de la sécurité des systèmes d''information doit formaliser et tenir à jour les documents validés par le Chef de département (sur son périmètre).', 'Mapping ISO 27001 : A.5.1', 6);

-- ============================================================
-- PER — Sécurité du personnel (13 contrôles)
-- Chapitre II — Objectifs 2, 3, 4
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
-- Objectif 2 : Sélection du personnel
('00000000-0000-0000-0008-000000000002', 'REG 2-1', 'Information des agents sur leurs responsabilités SSI', 'À l''embauche, les agents doivent être informés, au préalable, de leur rôle sur la sécurité de l''information et leurs responsabilités dans l''application effective de la politique de sécurité de l''organisme.', 'Mapping ISO 27001 : A.6.1, A.6.2', 1),
('00000000-0000-0000-0008-000000000002', 'REG 2-2', 'Engagement de comportement responsable', 'Les agents doivent s''engager à avoir un comportement responsable et qui ne représente aucun risque pour la sécurité de l''information.', 'Mapping ISO 27001 : A.6.2', 2),
('00000000-0000-0000-0008-000000000002', 'REG 2-3', 'Habilitation et charte de confidentialité', 'Les agents qui ont accès à l''information sensible et aux systèmes d''information doivent faire, au préalable, l''objet d''enquêtes de sécurité et de moralité, être habilités et signer une charte de confidentialité et de non-divulgation. Il doit en être de même pour les prestataires.', 'L''habilitation garantit que ces personnes peuvent, sans risque pour elles-mêmes, connaître des informations sensibles. Mapping ISO 27001 : A.6.1, A.6.6', 3),
('00000000-0000-0000-0008-000000000002', 'REG 2-4', 'Information sur les sanctions en cas de violation', 'Les agents qui ont accès à l''information sensible doivent être informés de leurs responsabilités en matière de sécurité et être prévenus des sanctions prévues en cas de violation de la politique de sécurité de l''organisme.', 'Sanctions : Code pénal art. 60-64 et 363. Loi 61-33 du 15 juin 1961 art. 14 (statut général des fonctionnaires).', 4),
('00000000-0000-0000-0008-000000000002', 'REG 2-5', 'Signalement obligatoire des incidents', 'Tout personnel utilisateur d''un système d''information, qui constate un événement susceptible de dénoter un incident de sécurité informatique, doit le signaler, sans délai, au service compétent.', 'Mapping ISO 27001 : A.6.8', 5),
('00000000-0000-0000-0008-000000000002', 'REG 2-6', 'Protection des données à caractère personnel', 'Les données à caractère personnel doivent être protégées et traitées conformément aux dispositions de la loi 2008-12 du 25 janvier 2008 portant sur la protection des données à caractère personnel.', 'Référence : Loi 2008-12 (CDP-SN). Mapping ISO 27001 : A.5.34', 6),

-- Objectif 3 : Affectation du personnel
('00000000-0000-0000-0008-000000000002', 'REG 3-1', 'Gestion des accès lors des mouvements de personnel', 'En cas de mouvement de personnel, de changement de personnel, ou en cas de rupture de contrat ou de fin de contrat, tous les aspects relatifs à la sécurité de l''information doivent être pris en compte : gestion et révocation des comptes et des droits d''accès, gestion du contrôle d''accès aux locaux, gestion des équipements mobiles, gestion du principe d''habilitation et des principes du besoin d''en connaître et d''utiliser.', 'Mapping ISO 27001 : A.6.1, A.6.5. Couvre arrivées, mutations, départs.', 7),

-- Objectif 4 : Formation et sensibilisation
('00000000-0000-0000-0008-000000000002', 'REG 4-1', 'Programme de sensibilisation et formation SSI', 'Un programme de sensibilisation et de formation à la sécurité des systèmes d''information doit être élaboré, revu et régulièrement mis à jour.', 'Mapping ISO 27001 : A.6.3', 8),
('00000000-0000-0000-0008-000000000002', 'REG 4-2', 'Cohérence du programme avec la politique de sécurité', 'Ce programme doit être cohérent avec la politique de sécurité de l''organisme.', 'Mapping ISO 27001 : A.6.3', 9),
('00000000-0000-0000-0008-000000000002', 'REG 4-3', 'Adaptation aux niveaux de responsabilité', 'Ce programme doit prendre en compte les différents niveaux de responsabilités des membres de l''organisme.', 'Sensibilisation adaptée : direction, AQSSI, ASSI, utilisateurs finaux.', 10),
('00000000-0000-0000-0008-000000000002', 'REG 4-4', 'Mise à jour intégrant les retours d''expérience', 'Ce programme doit être mis à jour régulièrement afin de prendre en compte les nouveaux agents et les enseignements tirés des incidents liés à la sécurité de l''information déjà survenus.', 'Mapping ISO 27001 : A.6.3', 11),
('00000000-0000-0000-0008-000000000002', 'REG 4-5', 'Engagement visible de la direction', 'Ce programme doit faire apparaître clairement l''engagement de la direction sur la problématique de la sécurité des systèmes d''information.', 'Mapping ISO 27001 : A.5.1, A.5.2', 12),
('00000000-0000-0000-0008-000000000002', 'REG 4-6', 'Formation continue et veille technologique', 'Un programme de formation continue doit être mis en place pour les agents chargés de veiller à l''application effective de la politique de sécurité, afin qu''ils soient informés sur les menaces et vulnérabilités les plus récentes (veille technologique).', 'Mapping ISO 27001 : A.5.7, A.6.3', 13);

-- ============================================================
-- ACQ — Acquisition et développement des SI (4 contrôles)
-- Chapitre III — Objectif 5
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000003', 'REG 5-1', 'Exigences de sécurité à l''acquisition de nouveaux systèmes', 'Il faut prendre en compte les exigences liées au contrôle d''accès, à la sensibilisation des utilisateurs, à la protection de la confidentialité, de la disponibilité et de l''intégrité de l''information, et à la journalisation, la surveillance et la détection de fuite de données.', 'Intégrer la sécurité à l''entame de chaque projet d''acquisition. Mapping ISO 27001 : A.8.25, A.8.26', 1),
('00000000-0000-0000-0008-000000000003', 'REG 5-2', 'Développement sécurisé des logiciels', 'Sécuriser les locaux utilisés pour le développement de logiciels et appliquer les recommandations relatives à la sécurité du langage choisi, notamment dans les phases de conception, du choix des référentiels, du contrôle des versions et de la correction du code source.', 'Mapping ISO 27001 : A.8.25, A.8.28, A.8.31', 2),
('00000000-0000-0000-0008-000000000003', 'REG 5-3', 'Application des normes et standards de développement sécurisé', 'Appliquer les normes et standards en vigueur sur le développement sécurisé d''applications (ISO, IEC, ...).', 'Mapping ISO 27001 : A.8.28', 3),
('00000000-0000-0000-0008-000000000003', 'REG 5-4', 'Externalisation du développement', 'En cas d''externalisation du développement de logiciels, le maître d''œuvre doit se conformer aux exigences de sécurité citées supra mais aussi considérer les problèmes relatifs aux licences d''utilisation, à la qualité du développement et aux tests de sécurité à réaliser pendant le développement.', 'Mapping ISO 27001 : A.8.30', 4);

-- ============================================================
-- ACT — Gestion des actifs (7 contrôles)
-- Chapitre IV — Objectif 6
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000004', 'REG 6-1', 'Inventaire précis des actifs', 'Procéder à un inventaire précis des actifs de l''organisme afin de les identifier et le mettre à jour.', 'Mapping ISO 27001 : A.5.9', 1),
('00000000-0000-0000-0008-000000000004', 'REG 6-2', 'Affectation des actifs à des responsables', 'Affecter les actifs à des responsables désignés et qui sont chargés d''assurer leur sécurité (classification, protection et contrôle d''accès).', 'Mapping ISO 27001 : A.5.9, A.5.10', 2),
('00000000-0000-0000-0008-000000000004', 'REG 6-3', 'Règles d''utilisation correcte des actifs', 'Identifier, documenter, et mettre en œuvre des règles d''utilisation correcte de l''information, des actifs associés à l''information et des moyens de traitement de l''information.', 'Mapping ISO 27001 : A.5.10', 3),
('00000000-0000-0000-0008-000000000004', 'REG 6-4', 'Restitution des actifs en fin de contrat/mission', 'Veiller à la restitution effective des actifs dans leur totalité, en cas de fin de contrat ou de mission.', 'Mapping ISO 27001 : A.5.11', 4),
('00000000-0000-0000-0008-000000000004', 'REG 6-5', 'Classification des informations selon leur sensibilité', 'Procéder à une classification des informations suivant leur sensibilité et leur caractère sensible (cf. Instruction présidentielle n° 0303/PR du 16 juillet 2003).', 'Niveaux : TRÈS SECRET, SECRET, CONFIDENTIEL. Mapping ISO 27001 : A.5.12, A.5.13', 5),
('00000000-0000-0000-0008-000000000004', 'REG 6-6', 'Protection des supports d''information amovibles', 'Les informations stockées dans des supports amovibles doivent être protégées contre toute divulgation, modification ou destruction.', 'Mapping ISO 27001 : A.7.10', 6),
('00000000-0000-0000-0008-000000000004', 'REG 6-7', 'Effacement sécurisé des matériels mis au rebut', 'Pour les matériels qui doivent être mis au rebut, il faut procéder à un effacement sécurisé des données qui y sont stockées tel que défini par l''Instruction présidentielle n° 0303/PR du 16 juillet 2003.', 'Mapping ISO 27001 : A.7.14, A.8.10', 7);

-- ============================================================
-- FRN — Relation avec les fournisseurs (9 contrôles)
-- Chapitre V — Objectif 7
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000005', 'REG 7-1', 'Politique de sécurité applicable aux fournisseurs', 'Mettre en place une politique de sécurité applicable aux différents fournisseurs (logistique, finance, informatique, …).', 'Mapping ISO 27001 : A.5.19', 1),
('00000000-0000-0000-0008-000000000005', 'REG 7-2', 'Procédures de surveillance de la conformité fournisseurs', 'Mettre en œuvre des procédures permettant de surveiller la conformité aux exigences de sécurité de l''information pour chaque fournisseur.', 'Mapping ISO 27001 : A.5.22', 2),
('00000000-0000-0000-0008-000000000005', 'REG 7-3', 'Programme de sensibilisation des fournisseurs', 'Mettre en place un programme de sensibilisation du personnel en contact avec les fournisseurs sur les règles de sécurité applicables à ces derniers ainsi que sur le niveau d''accès aux systèmes d''information.', 'Mapping ISO 27001 : A.5.19, A.5.20', 3),
('00000000-0000-0000-0008-000000000005', 'REG 7-4', 'Charte de sécurité signée par les fournisseurs', 'Mettre en place une charte de sécurité signée par les différentes parties qui doivent s''engager à en respecter scrupuleusement les clauses.', 'Mapping ISO 27001 : A.5.20', 4),
('00000000-0000-0000-0008-000000000005', 'REG 7-5', 'Rappel des exigences légales et réglementaires', 'Rappeler les exigences légales et réglementaires sur les lois relatives à la protection des données à caractère personnel, sur les droits d''auteur et sur la propriété intellectuelle, et veiller à leur respect.', 'Référence : Loi 2008-12. Mapping ISO 27001 : A.5.31, A.5.32', 5),
('00000000-0000-0000-0008-000000000005', 'REG 7-6', 'Point focal sécurité pour les fournisseurs', 'Mettre en place un point focal qui sera chargé de communiquer sur les questions de sécurité avec les fournisseurs.', 'Mapping ISO 27001 : A.5.19', 6),
('00000000-0000-0000-0008-000000000005', 'REG 7-7', 'Prise en compte des sous-traitants', 'Tous les intervenants doivent être pris en compte, notamment les sous-traitants qui travaillent pour le compte de fournisseurs.', 'Mapping ISO 27001 : A.5.21', 7),
('00000000-0000-0000-0008-000000000005', 'REG 7-8', 'Intégration de la sécurité dans la chaîne d''approvisionnement', 'Les clauses contractuelles entre les fournisseurs et l''entité doivent intégrer toute la chaîne d''approvisionnement informatique : conformité avec les normes relatives à la sécurité des produits informatiques, publication des exigences de sécurité satisfaites par leurs produits et en fournir la preuve.', 'Mapping ISO 27001 : A.5.21, A.5.23', 8),
('00000000-0000-0000-0008-000000000005', 'REG 7-9', 'Procédures d''audit des prestations fournisseurs', 'Mettre en place des procédures d''audit sur les prestations effectuées par les fournisseurs ainsi que sur la qualité de ces services.', 'Mapping ISO 27001 : A.5.22', 9);

-- ============================================================
-- PHY — Sécurité physique (48 contrôles)
-- Chapitre VI — Objectifs 8 à 16
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
-- Obj. 8 : Périmètres de sécurité physique
('00000000-0000-0000-0008-000000000006', 'REG 8-1', 'Zones sécurisées identifiées et définies', 'Tous les centres de données, les salles des serveurs, les salles d''exploitation, les salles de commutation, les installations de stockage, les salles de service et les salles des équipements réseau doivent être considérées comme des zones sécurisées.', 'Mapping ISO 27001 : A.7.1', 1),
('00000000-0000-0000-0008-000000000006', 'REG 8-2', 'Contrôle d''accès par autorisation écrite ou badge', 'L''accès à ces zones ne doit être permis qu''au personnel muni d''une autorisation écrite ou d''un badge délivré par le responsable désigné.', 'Mapping ISO 27001 : A.7.2', 2),
('00000000-0000-0000-0008-000000000006', 'REG 8-3', 'Registre d''accès aux zones sécurisées', 'Un registre d''accès doit être tenu à l''entrée de chaque zone sécurisée. Il doit contenir l''identité, le but, la signature, l''heure d''entrée et de sortie de toute personne accédant au site.', 'Mapping ISO 27001 : A.7.2', 3),
('00000000-0000-0000-0008-000000000006', 'REG 8-4', 'Agent de sécurité à l''entrée des sites sensibles', 'Un agent de sécurité doit être placé à l''entrée de chaque site sensible, chargé de : interdiction d''accès au personnel non autorisé, inscription au registre d''accès, contrôle des bagages, gestion des alarmes et appels d''urgence.', 'Mapping ISO 27001 : A.7.2', 4),
('00000000-0000-0000-0008-000000000006', 'REG 8-5', 'Fermeture et verrouillage hors heures de service', 'Les zones sécurisées doivent être fermées en dehors des heures de service. Toutes les fenêtres, portes, et issues de secours doivent être verrouillées. Tous les conduits (climatisation, élévateurs…) doivent être munis de grilles métalliques.', 'Mapping ISO 27001 : A.7.1, A.7.3', 5),
('00000000-0000-0000-0008-000000000006', 'REG 8-6', 'Révocation immédiate des droits d''accès', 'Tous les droits d''accès doivent être immédiatement révoqués en cas de départ à la retraite de l''agent, de démission, de suspension, de mutation ou de congé de longue durée.', 'Mapping ISO 27001 : A.5.11, A.7.2', 6),
('00000000-0000-0000-0008-000000000006', 'REG 8-7', 'Sauvegarde des enregistrements d''accès', 'Les enregistrements d''accès doivent être régulièrement sauvegardés et conservés pendant une période déterminée.', 'Mapping ISO 27001 : A.7.2, A.7.4', 7),
('00000000-0000-0000-0008-000000000006', 'REG 8-8', 'Choix des équipements par l''ASSI selon analyse de risque', 'Chaque ASSI doit choisir les techniques et les équipements appropriés sur la base des résultats d''une évaluation de risque physique et d''une analyse des coûts de contre-mesures ou des avantages associés.', 'Mapping ISO 27001 : A.7.1', 8),

-- Obj. 9 : Contrôle d'entrée physique
('00000000-0000-0000-0008-000000000006', 'REG 9-1', 'Entrée sur carte d''accès visiteur', 'L''entrée est autorisée sur présentation de la carte d''accès visiteur. L''identité du visiteur, le but de sa visite, l''heure d''entrée et de sortie doivent être inscrits dans un registre. Il faut authentifier l''identité du visiteur à l''aide d''un moyen approprié.', 'Mapping ISO 27001 : A.7.2', 9),
('00000000-0000-0000-0008-000000000006', 'REG 9-2', 'Visites hors heures de service interdites', 'Les visites ne sont pas autorisées en dehors des heures de service ou de pause.', 'Mapping ISO 27001 : A.7.2', 10),
('00000000-0000-0000-0008-000000000006', 'REG 9-3', 'Port d''identification visible obligatoire', 'Tous les agents doivent porter un moyen d''identification visible ; ils doivent immédiatement aviser le personnel de sécurité s''ils rencontrent des visiteurs non accompagnés et toute personne ne portant pas d''identification visible (exemple : port de badge).', 'Mapping ISO 27001 : A.7.2', 11),
('00000000-0000-0000-0008-000000000006', 'REG 9-4', 'Accès salle de serveurs limité aux personnes autorisées', 'L''accès à la salle de serveurs doit être limité aux seules personnes autorisées.', 'Mapping ISO 27001 : A.7.2', 12),

-- Obj. 10 : Sécurisation des bureaux et équipements
('00000000-0000-0000-0008-000000000006', 'REG 10-1', 'Équipements clés dans des emplacements non accessibles au public', 'Les équipements-clés doivent être installés dans un emplacement non accessible au public. Ils doivent être configurés de manière à empêcher toute fuite d''information sensible, notamment par rayonnement électromagnétique (mise en place de cages de faraday).', 'Mapping ISO 27001 : A.7.3, A.7.8', 13),
('00000000-0000-0000-0008-000000000006', 'REG 10-2', 'Répertoires internes non accessibles sans autorisation', 'Les répertoires et les annuaires téléphoniques internes, identifiant les emplacements des moyens de traitement de l''information sensible, ne doivent pas être facilement accessibles sans autorisation.', 'Mapping ISO 27001 : A.7.3', 14),
('00000000-0000-0000-0008-000000000006', 'REG 10-3', 'Discrétion des bâtiments', 'Les bâtiments doivent être discrets et ne donner que le minimum d''indications sur leur usage, sans signe évident identifiant la présence d''activités de traitement de l''information.', 'Mapping ISO 27001 : A.7.1', 15),

-- Obj. 11 : Travail dans les zones sécurisées
('00000000-0000-0000-0008-000000000006', 'REG 11-1', 'Accès sur la base du besoin d''en connaître', 'Le personnel doit être informé de l''existence de zones sécurisées et qu''il n''y a accès que sur la seule base des principes du besoin d''en connaître et d''utiliser.', 'Mapping ISO 27001 : A.7.6', 16),
('00000000-0000-0000-0008-000000000006', 'REG 11-2', 'Travail sans surveillance évité', 'Le travail sans surveillance dans les zones sécurisées doit être évité pour des raisons de sécurité.', 'Mapping ISO 27001 : A.7.6', 17),
('00000000-0000-0000-0008-000000000006', 'REG 11-3', 'Verrouillage des zones inoccupées', 'Les zones sécurisées inoccupées doivent être physiquement verrouillées et contrôlées périodiquement.', 'Mapping ISO 27001 : A.7.6', 18),
('00000000-0000-0000-0008-000000000006', 'REG 11-4', 'Interdiction d''équipements photo/vidéo/audio', 'L''utilisation d''équipements photo, vidéo, audio ou d''autres dispositifs tels que les caméras intégrées à des appareils mobiles, doit être interdite, sauf autorisation.', 'Mapping ISO 27001 : A.7.6', 19),

-- Obj. 12 : Zones de livraison et de chargement
('00000000-0000-0000-0008-000000000006', 'REG 12-1', 'Zone d''approvisionnement à accès restreint', 'Désigner la zone d''approvisionnement pour les matières entrantes (accès restreint au personnel de livraison).', 'Mapping ISO 27001 : A.7.2', 20),
('00000000-0000-0000-0008-000000000006', 'REG 12-2', 'Inspection des matières entrantes', 'Inspecter les matières entrantes, par des équipements appropriés, pour vérifier la présence éventuelle de substances dangereuses (explosives, chimiques, ou autres) avant qu''elles ne quittent la zone de livraison.', 'Mapping ISO 27001 : A.7.2', 21),
('00000000-0000-0000-0008-000000000006', 'REG 12-3', 'Enregistrement des matières dès l''arrivée', 'Enregistrer les matières entrantes dès leur arrivée sur le site conformément aux procédures d''enregistrement des actifs.', 'Mapping ISO 27001 : A.5.9', 22),
('00000000-0000-0000-0008-000000000006', 'REG 12-4', 'Comptabilité des équipements par les directions', 'Toute la comptabilité matière doit être effectuée par les directions chargées des équipements dans les différentes entités.', 'Mapping ISO 27001 : A.5.9', 23),

-- Obj. 13 : Emplacement et protection des matériels
('00000000-0000-0000-0008-000000000006', 'REG 13-1', 'Systèmes d''alarme périodiquement contrôlés', 'Les installations sensibles doivent être équipées de systèmes d''alarme périodiquement contrôlés.', 'Mapping ISO 27001 : A.7.3, A.7.4', 24),
('00000000-0000-0000-0008-000000000006', 'REG 13-2', 'Matériel en salles sécurisées, portes et fenêtres protégées', 'Tout le matériel doit être installé dans des salles sécurisées. Les portes et les fenêtres ne doivent pas être des moyens d''accès ou de connexion au matériel, de l''extérieur de la zone sécurisée. Des issues de secours doivent être prévues dans tous les sites.', 'Mapping ISO 27001 : A.7.3', 25),
('00000000-0000-0000-0008-000000000006', 'REG 13-3', 'Détection et lutte contre l''incendie', 'Dans tous les sites sensibles, des dispositifs de détection et de lutte contre l''incendie tels que les détecteurs de fumée et les extincteurs, doivent être installés, contrôlés et testés régulièrement.', 'Mapping ISO 27001 : A.7.5', 26),
('00000000-0000-0000-0008-000000000006', 'REG 13-4', 'Sites en briques réfractaires, sans matériel inflammable', 'Les sites sensibles doivent être en briques réfractaires et ne doivent contenir aucun matériel inflammable tel que des meubles en bois, des rideaux ou des tapis.', 'Mapping ISO 27001 : A.7.5', 27),
('00000000-0000-0000-0008-000000000006', 'REG 13-5', 'Conformité des installations électriques', 'Il faut utiliser les spécifications techniques des fabricants des matériels électriques et se conformer aux normes de sécurité électrique des sociétés locales prestataires d''électricité pour empêcher les incendies.', 'Mapping ISO 27001 : A.7.5', 28),
('00000000-0000-0000-0008-000000000006', 'REG 13-6', 'Inspection et test régulier des installations électriques', 'Il faut faire inspecter et tester régulièrement les installations électriques pour s''assurer de leur bon fonctionnement (systèmes d''éclairage, interrupteurs, câbles électriques, générateur de secours, …).', 'Mapping ISO 27001 : A.7.5', 29),
('00000000-0000-0000-0008-000000000006', 'REG 13-7', 'Alimentation électrique d''urgence par générateur de secours', 'Une alimentation électrique d''urgence doit être sauvegardée par un générateur de secours.', 'Mapping ISO 27001 : A.7.11', 30),
('00000000-0000-0000-0008-000000000006', 'REG 13-8', 'Alimentation électrique permanente pour équipements sensibles', 'Tous les équipements sensibles doivent disposer d''une alimentation électrique permanente.', 'Mapping ISO 27001 : A.7.11', 31),
('00000000-0000-0000-0008-000000000006', 'REG 13-9', 'Matériel sur support surélevé avec détection de fuite d''eau', 'Le matériel doit être installé sur un support surélevé. Des systèmes de détection de fuite d''eau doivent être installés dans les sites sensibles.', 'Mapping ISO 27001 : A.7.5', 32),
('00000000-0000-0000-0008-000000000006', 'REG 13-10', 'Climatisation, ventilation et humidité contrôlées', 'Des systèmes de climatisation, de ventilation, d''alimentation en gaz et d''évacuation des eaux usées doivent être installés, entretenus et vérifiés régulièrement pour empêcher d''éventuels endommagements des actifs et l''interruption des activités de l''entité. Des appareils de mesure de l''humidité et de la température doivent être prévus.', 'Mapping ISO 27001 : A.7.5', 33),
('00000000-0000-0000-0008-000000000006', 'REG 13-11', 'Sites de reprise à distance du site principal', 'Les sites de reprise sur sinistre et de stockage de données doivent être installés à des endroits très éloignés du site principal.', 'Mapping ISO 27001 : A.7.5, A.8.14', 34),
('00000000-0000-0000-0008-000000000006', 'REG 13-12', 'Stockage sécurisé des matériels défectueux', 'Le matériel ou le support de stockage défectueux et les pièces de rechange, mis au rebut, doivent être stockés dans une pièce séparée qui doit être en permanence verrouillée.', 'Mapping ISO 27001 : A.7.14', 35),
('00000000-0000-0000-0008-000000000006', 'REG 13-13', 'Racks et baies sans signe descriptif', 'La salle d''équipements et les racks ne doivent comporter aucun signe écrit décrivant leurs noms, leurs buts, les diagrammes de réseau, les numéros de ports, les adresses IP, etc.', 'Mapping ISO 27001 : A.7.3', 36),
('00000000-0000-0000-0008-000000000006', 'REG 13-14', 'Nettoyage régulier des équipements', 'Les équipements doivent être nettoyés régulièrement pour éviter notamment la poussière.', 'Mapping ISO 27001 : A.7.3', 37),
('00000000-0000-0000-0008-000000000006', 'REG 13-15', 'Interdiction d''activités non prévues dans les salles sensibles', 'Il doit être strictement interdit d''effectuer des activités autres que celles prévues dans les salles abritant des équipements sensibles.', 'Mapping ISO 27001 : A.7.6', 38),
('00000000-0000-0000-0008-000000000006', 'REG 13-16', 'Interdiction de manger, boire et fumer', 'Il doit être strictement interdit de manger, de boire et de fumer à l''intérieur de la zone sécurisée.', 'Mapping ISO 27001 : A.7.6', 39),

-- Obj. 14 : Sécurité du câblage
('00000000-0000-0000-0008-000000000006', 'REG 14-1', 'Câbles enterrés autant que possible', 'Les lignes électriques et les lignes de télécommunication branchées aux systèmes d''information doivent être enterrées autant que faire se peut, par mesure de sécurité.', 'Mapping ISO 27001 : A.7.12', 40),
('00000000-0000-0000-0008-000000000006', 'REG 14-2', 'Séparation câbles électriques et télécommunication', 'Les câbles électriques doivent être séparés des câbles de télécommunication pour empêcher les interférences.', 'Mapping ISO 27001 : A.7.12', 41),
('00000000-0000-0000-0008-000000000006', 'REG 14-3', 'Câbles de télécommunication fiables dans des conduits', 'Tous les câbles de télécommunication doivent être fiables et installés dans des conduits. Des câbles redondants doivent être installés pour assurer une reprise rapide des services.', 'Mapping ISO 27001 : A.7.12', 42),
('00000000-0000-0000-0008-000000000006', 'REG 14-4', 'Câbles électriques dans des conduits appropriés', 'Les câbles électriques doivent être installés dans des conduits appropriés.', 'Mapping ISO 27001 : A.7.12', 43),
('00000000-0000-0000-0008-000000000006', 'REG 14-5', 'Panneaux de brassage et chambres de câblage isolés', 'Les panneaux de brassage et les salles des câbles doivent être isolés des zones d''accueil du public avec un accès contrôlé.', 'Mapping ISO 27001 : A.7.12', 44),
('00000000-0000-0000-0008-000000000006', 'REG 14-6', 'Panneaux de répartition électrique à accès limité', 'Les panneaux de répartition électrique ainsi que les chambres de câblage doivent être strictement contrôlés et l''accès limité au personnel autorisé.', 'Mapping ISO 27001 : A.7.12', 45),
('00000000-0000-0000-0008-000000000006', 'REG 14-7', 'Paratonnerre et parafoudres sur sites sensibles', 'Tous les sites sensibles doivent être équipés de paratonnerres et de parafoudres pour protéger respectivement les bâtiments et les matériels.', 'Mapping ISO 27001 : A.7.5, A.7.12', 46),

-- Obj. 15 : Maintenance des matériels
('00000000-0000-0000-0008-000000000006', 'REG 15-1', 'Maintenance par personnel autorisé uniquement', 'Seul le personnel autorisé doit effectuer le service de maintenance.', 'Mapping ISO 27001 : A.7.13', 47),
('00000000-0000-0000-0008-000000000006', 'REG 15-2', 'Contrat de maintenance avec fournisseurs accrédités', 'Les unités de maintenance doivent établir un contrat avec les fournisseurs accrédités, immédiatement après la mise en service du matériel.', 'Mapping ISO 27001 : A.7.13', 48),
('00000000-0000-0000-0008-000000000006', 'REG 15-3', 'Clauses contractuelles de qualité et disponibilité', 'Les clauses du contrat doivent tenir compte des intérêts de l''organisme : qualité de service, disponibilité, temps de réponse, politiques de rechange, modalités de paiement. Le responsable de l''entité doit approuver le contrat.', 'Mapping ISO 27001 : A.7.13', 49),
('00000000-0000-0000-0008-000000000006', 'REG 15-4', 'Registre de maintenance', 'Les unités de maintenance doivent ouvrir un registre pour la traçabilité de leur travail, des paiements effectués, de la qualité, de la performance et de l''expiration du contrat.', 'Mapping ISO 27001 : A.7.13', 50),
('00000000-0000-0000-0008-000000000006', 'REG 15-5', 'Approbation du travail fournisseur par les administrateurs', 'Le travail effectué par les fournisseurs doit être approuvé, notamment par les administrateurs systèmes, réseaux et de bases de données ; ils doivent tenir un registre à ce sujet.', 'Mapping ISO 27001 : A.7.13', 51),
('00000000-0000-0000-0008-000000000006', 'REG 15-6', 'Surveillance étroite des activités de maintenance', 'Les activités de maintenance doivent être effectuées sous une surveillance étroite et adéquate des ASSI. En cas d''intervention d''un prestataire, les ASSI doivent toujours être présents et veiller à ce qu''aucun fichier ou programme de données ne soit copié.', 'Mapping ISO 27001 : A.7.13', 52),
('00000000-0000-0000-0008-000000000006', 'REG 15-7', 'Conservation des dossiers de maintenance', 'Les dossiers de maintenance doivent être conservés pour suivi.', 'Mapping ISO 27001 : A.7.13', 53),
('00000000-0000-0000-0008-000000000006', 'REG 15-8', 'Sauvegarde des données avant remise en réparation', 'En cas de remise d''un équipement pour réparation, les données qui y sont contenues doivent être sauvegardées dans d''autres supports et être supprimées de manière sécurisée.', 'Mapping ISO 27001 : A.7.14, A.8.10', 54),

-- Obj. 16 : Bureau propre et écran vide
('00000000-0000-0000-0008-000000000006', 'REG 16-1', 'Supports amovibles sensibles en coffre ou armoire', 'Les supports amovibles de stockage de données sensibles (disques durs, disquettes, bandes magnétiques, CDROM, DVD, Blu-ray, clés USB, cartes SD, cartes à puces …) doivent être conservés dans un coffre ou une armoire au même titre que les documents et correspondances sensibles sur support papier.', 'Mapping ISO 27001 : A.7.7', 55),
('00000000-0000-0000-0008-000000000006', 'REG 16-2', 'Clés des locaux en endroit sûr hors heures de travail', 'Après les heures de travail ou en l''absence des utilisateurs, les clefs des locaux, des coffres et des armoires doivent être gardées dans un endroit sûr accessible aux seules personnes autorisées.', 'Mapping ISO 27001 : A.7.7', 56),
('00000000-0000-0000-0008-000000000006', 'REG 16-3', 'Effacement logique et physique des fichiers classifiés périmés', 'Les fichiers contenant des informations classifiées et qui sont périmées doivent être effacés. Cette destruction ne doit pas être uniquement logique mais doit être accompagnée d''un effacement physique pour prévenir toute possibilité de lecture.', 'Mapping ISO 27001 : A.8.10', 57),
('00000000-0000-0000-0008-000000000006', 'REG 16-4', 'Retrait immédiat des documents sensibles des imprimantes', 'Les documents contenant des informations sensibles ou classifiées doivent être immédiatement retirés des imprimantes, des photocopieuses, des scanneurs, des appareils de télécopie après leur utilisation.', 'Mapping ISO 27001 : A.7.7', 58),
('00000000-0000-0000-0008-000000000006', 'REG 16-5', 'Verrouillage automatique des postes en absence', 'En l''absence de leurs utilisateurs, les ordinateurs et les terminaux doivent être déconnectés ou protégés par un verrouillage automatique (délai court) de l''écran ou du clavier contrôlé par un mot de passe ou un autre mécanisme d''authentification.', 'Mapping ISO 27001 : A.7.7, A.8.1', 59),
('00000000-0000-0000-0008-000000000006', 'REG 16-6', 'Interdiction de reproduction non autorisée', 'L''utilisation non autorisée des photocopieurs et autres appareils de reproduction (par exemple les scanneurs ou les appareils photo numériques) doit être strictement interdite.', 'Mapping ISO 27001 : A.7.7', 60),
('00000000-0000-0000-0008-000000000006', 'REG 16-7', 'Impression sécurisée par identification', 'Il faut utiliser des imprimantes dotées d''une fonction d''identification par code personnel, afin que seules les personnes ayant initié une tâche d''impression puissent récupérer leurs documents imprimés et uniquement lorsqu''elles se trouvent à proximité de l''imprimante.', 'Mapping ISO 27001 : A.7.7', 61);

-- ============================================================
-- LOG — Sécurité logique (31 contrôles)
-- Chapitre VII — Objectifs 17, 18, 19
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
-- Obj. 17 : Sécurité des accès
('00000000-0000-0000-0008-000000000007', 'REG 17-1', 'Mesures de sécurité pour les applications métier', 'Spécifier les mesures de sécurité pour les applications métier.', 'Mapping ISO 27001 : A.8.3', 1),
('00000000-0000-0000-0008-000000000007', 'REG 17-2', 'Principe du besoin d''en connaître', 'Appliquer le principe du besoin d''en connaître : « Nul ne peut, du seul fait de son grade ou son titre, avoir accès aux informations sensibles s''il n''est pas habilité et s''il n''a pas besoin d''en connaître pour réaliser ses tâches ».', 'Mapping ISO 27001 : A.5.15, A.8.3', 2),
('00000000-0000-0000-0008-000000000007', 'REG 17-3', 'Principe du besoin d''utiliser', 'Appliquer le principe du besoin d''utiliser : « Nul ne peut, du seul fait de son grade ou son titre, avoir accès aux moyens de traitement des informations sensibles, s''il n''est pas habilité et s''il n''a pas besoin de les utiliser pour accomplir son travail ».', 'Mapping ISO 27001 : A.5.15, A.8.3', 3),
('00000000-0000-0000-0008-000000000007', 'REG 17-4', 'Cloisonnement des rôles pour le contrôle des accès', 'Effectuer un cloisonnement des rôles pour le contrôle des accès.', 'Mapping ISO 27001 : A.5.3', 4),
('00000000-0000-0000-0008-000000000007', 'REG 17-5', 'Mise à jour régulière des droits d''accès', 'Mettre à jour régulièrement les droits d''accès attribués aux utilisateurs.', 'Mapping ISO 27001 : A.5.18', 5),
('00000000-0000-0000-0008-000000000007', 'REG 17-6', 'Revue des privilèges en cas de changement de poste', 'Revoir régulièrement les privilèges et les droits d''accès en cas de changement de poste de travail.', 'Mapping ISO 27001 : A.5.18', 6),

-- Obj. 18 : Sécurité des applicatifs
('00000000-0000-0000-0008-000000000007', 'REG 18-1', 'Mécanisme de contrôle d''accès aux fonctions applicatives', 'Un mécanisme permettant de contrôler l''accès aux fonctions d''application système doit être mis en place.', 'Mapping ISO 27001 : A.8.2, A.8.3', 7),
('00000000-0000-0000-0008-000000000007', 'REG 18-2', 'Contrôle des droits d''accès utilisateurs (lecture, écriture, suppression)', 'Les droits d''accès des utilisateurs doivent être contrôlés (lecture, écriture, suppression, …).', 'Mapping ISO 27001 : A.8.3', 8),
('00000000-0000-0000-0008-000000000007', 'REG 18-3', 'Accès aux applications par mécanisme de connexion sécurisée', 'Il faut restreindre l''accès aux applications par un mécanisme de connexion sécurisée.', 'Mapping ISO 27001 : A.8.5', 9),
('00000000-0000-0000-0008-000000000007', 'REG 18-4', 'Authentification forte pour données classifiées', 'Une technologie d''authentification forte doit être utilisée lorsque les données sont classifiées.', 'Mapping ISO 27001 : A.8.5', 10),
('00000000-0000-0000-0008-000000000007', 'REG 18-5', 'Limitation des tentatives de connexion non autorisées', 'Il faut limiter le nombre de connexions non autorisées aux applications.', 'Mapping ISO 27001 : A.8.5', 11),
('00000000-0000-0000-0008-000000000007', 'REG 18-6', 'Pas d''informations révélatrices lors d''une connexion échouée', 'Il ne faut pas afficher d''informations qui peuvent fournir des indications lors d''une tentative de connexion non autorisée.', 'Mapping ISO 27001 : A.8.5', 12),
('00000000-0000-0000-0008-000000000007', 'REG 18-7', 'Changement impératif des mots de passe par défaut', 'Les mots de passe par défaut doivent être changés impérativement.', 'Mapping ISO 27001 : A.5.17', 13),
('00000000-0000-0000-0008-000000000007', 'REG 18-8', 'Fermeture des sessions inactives et journalisation', 'Il faut mettre en place un système de contrôle des tentatives de connexion automatique et fermer les sessions inactives au bout d''un certain temps d''inactivité. Toutes les tentatives de connexion doivent être journalisées.', 'Mapping ISO 27001 : A.8.1, A.8.15', 14),
('00000000-0000-0000-0008-000000000007', 'REG 18-9', 'Mots de passe robustes, non transmis en clair', 'Les mots de passe doivent être robustes. Ils ne doivent pas être transmis en clair. Il faut les changer régulièrement suivant une périodicité définie.', 'Mapping ISO 27001 : A.5.17', 15),
('00000000-0000-0000-0008-000000000007', 'REG 18-10', 'Interdiction d''installation de logiciels sans autorisation ASSI', 'Il faut prévenir rigoureusement et interdire formellement l''installation de logiciels sans l''autorisation de l''Agent de la Sécurité des Systèmes d''Information (ASSI).', 'Mapping ISO 27001 : A.8.19', 16),
('00000000-0000-0000-0008-000000000007', 'REG 18-11', 'Désinstallation des applications non indispensables', 'Les applications ou utilitaires non indispensables doivent être désinstallées.', 'Mapping ISO 27001 : A.8.19', 17),
('00000000-0000-0000-0008-000000000007', 'REG 18-12', 'Contrôle de l''accès au code source', 'L''accès au code source des applications doit être contrôlé afin d''en assurer l''intégrité.', 'Mapping ISO 27001 : A.8.4', 18),

-- Obj. 19 : Sécurité des échanges
('00000000-0000-0000-0008-000000000007', 'REG 19-1', 'Politique d''accès réseau avec exigences d''authentification', 'Il faut mettre en place une politique d''accès aux réseaux de l''entité, qui précise les exigences d''authentification des utilisateurs.', 'Mapping ISO 27001 : A.8.20, A.8.21', 19),
('00000000-0000-0000-0008-000000000007', 'REG 19-2', 'Responsabilités et procédures de gestion des équipements réseau', 'Il faut définir les responsabilités et les procédures de gestion des équipements réseau.', 'Mapping ISO 27001 : A.8.20', 20),
('00000000-0000-0000-0008-000000000007', 'REG 19-3', 'Transmission conforme à la législation', 'Les moyens de transmission de l''information doivent être conformes à la législation en vigueur.', 'Mapping ISO 27001 : A.5.14', 21),
('00000000-0000-0000-0008-000000000007', 'REG 19-4', 'Surveillance et journalisation des activités réseau', 'Il faut mettre en place un mécanisme de surveillance et de journalisation de toutes les activités dans le réseau.', 'Mapping ISO 27001 : A.8.15, A.8.16', 22),
('00000000-0000-0000-0008-000000000007', 'REG 19-5', 'Protection des données sur réseaux publics selon la classification', 'Les données transmises via les réseaux publics doivent être protégées selon leur niveau de classification. Il faut utiliser les réseaux de l''État, autant que faire se peut, pour transmettre des données hors de l''entité.', 'Mapping ISO 27001 : A.5.14, A.8.24', 23),
('00000000-0000-0000-0008-000000000007', 'REG 19-6', 'Sécurisation des services réseau (authentification, chiffrement, non-répudiation)', 'Les services de réseau doivent, en accord avec le fournisseur, être sécurisés par des fonctions de sécurité : l''authentification, l''intégrité, le chiffrement, la non-répudiation et les contrôles de connexion réseau.', 'Mapping ISO 27001 : A.8.20, A.8.24', 24),
('00000000-0000-0000-0008-000000000007', 'REG 19-7', 'Analyse de risques pour les réseaux sans fil', 'Le déploiement de réseaux sans fil doit faire l''objet d''une analyse de risques spécifiques. Des mesures complémentaires doivent être prises dans le cadre de la défense en profondeur. En particulier, une segmentation du réseau doit être mise en place.', 'Mapping ISO 27001 : A.8.20, A.8.22', 25),
('00000000-0000-0000-0008-000000000007', 'REG 19-8', 'Cloisonnement physique et/ou logique des réseaux', 'Il faut effectuer un cloisonnement, physique et/ou logique des réseaux informatiques, suivant un critère bien défini pour séparer les réseaux : par service administratif, par niveau de sécurité, etc.', 'Mapping ISO 27001 : A.8.22', 26),
('00000000-0000-0000-0008-000000000007', 'REG 19-9-1', 'Algorithmes de chiffrement labellisés par la Commission nationale de cryptologie', 'Il faut choisir des algorithmes de chiffrement labellisés par la Commission nationale de cryptologie.', 'Référence : Loi 2008-41 du 20 août 2008 portant sur la cryptologie. Mapping ISO 27001 : A.8.24', 27),
('00000000-0000-0000-0008-000000000007', 'REG 19-9-5', 'Authentification forte et chiffrement de la messagerie', 'Il faut mettre en place un système d''authentification forte et un système de chiffrement pour sécuriser la messagerie électronique de l''entité.', 'Mapping ISO 27001 : A.5.14, A.8.24', 28),
('00000000-0000-0000-0008-000000000007', 'REG 19-9-7', 'Chiffrement des disques contenant des informations sensibles', 'Chiffrer une ou plusieurs parties des disques durs des systèmes d''information contenant les informations sensibles.', 'Mapping ISO 27001 : A.8.24', 29),
('00000000-0000-0000-0008-000000000007', 'REG 19-9-11', 'Longueurs de clés conformes aux recommandations', 'Il faut choisir des longueurs de clefs de chiffrement conformes aux recommandations de la Commission nationale de cryptologie.', 'Mapping ISO 27001 : A.8.24', 30),
('00000000-0000-0000-0008-000000000007', 'REG 19-9-12', 'Politique rigoureuse de gestion des clés de chiffrement', 'Il faut mettre en œuvre une politique rigoureuse de gestion des clefs de chiffrement afin d''en assurer la protection, sans faille, durant tout leur cycle de vie.', 'Mapping ISO 27001 : A.8.24', 31);

-- ============================================================
-- EXP — Sécurité de l'exploitation (37 contrôles)
-- Chapitre VIII — Objectifs 20 à 27
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
-- Obj. 20 : Procédures d'exploitation documentées
('00000000-0000-0000-0008-000000000008', 'REG 20-1', 'Procédures d''installation et configuration documentées', 'Des procédures bien documentées doivent être établies pour l''installation et la configuration des systèmes.', 'Mapping ISO 27001 : A.5.37', 1),
('00000000-0000-0000-0008-000000000008', 'REG 20-2', 'Procédures de redémarrage et récupération documentées', 'Une procédure bien documentée de redémarrage et de récupération de chaque système, en cas de défaillance, doit être définie et appliquée.', 'Mapping ISO 27001 : A.5.37', 2),
('00000000-0000-0000-0008-000000000008', 'REG 20-3', 'Procédures de sauvegarde et maintenance documentées', 'Une procédure bien documentée de sauvegarde et de maintenance, pour chaque système, doit être définie et appliquée.', 'Mapping ISO 27001 : A.5.37, A.8.13', 3),
('00000000-0000-0000-0008-000000000008', 'REG 20-4', 'Contacts support technique disponibles et à jour', 'Les contacts du support technique doivent être disponibles et tenus à jour, pour faire face notamment aux difficultés d''exploitation.', 'Mapping ISO 27001 : A.5.37', 4),
('00000000-0000-0000-0008-000000000008', 'REG 20-5', 'Normes de sécurité des équipements documentées et suivies', 'Les normes de sécurité de l''équipement doivent être documentées et suivies.', 'Mapping ISO 27001 : A.5.37', 5),
('00000000-0000-0000-0008-000000000008', 'REG 20-6', 'Interdiction d''installer des logiciels sans rapport avec l''activité', 'L''installation de logiciels n''ayant aucun rapport avec les activités de l''entité doit être prohibée.', 'Mapping ISO 27001 : A.8.19', 6),
('00000000-0000-0000-0008-000000000008', 'REG 20-7', 'Interdiction d''utiliser des logiciels non autorisés ou sans licence', 'L''utilisation de logiciels non autorisés, et sans une licence authentique, doit être strictement interdite.', 'Mapping ISO 27001 : A.5.32, A.8.19', 7),
('00000000-0000-0000-0008-000000000008', 'REG 20-8', 'Audit régulier des procédures d''exploitation', 'Les procédures d''exploitation doivent être régulièrement auditées, contrôlées et mises à jour.', 'Mapping ISO 27001 : A.5.37', 8),

-- Obj. 21 : Gestion des changements
('00000000-0000-0000-0008-000000000008', 'REG 21-1', 'Identification et consignation des changements significatifs', 'Il faut identifier et consigner les changements significatifs.', 'Mapping ISO 27001 : A.8.32', 9),
('00000000-0000-0000-0008-000000000008', 'REG 21-2', 'Planification des changements et des tests', 'Il faut planifier les changements et la phase de test.', 'Mapping ISO 27001 : A.8.32', 10),
('00000000-0000-0000-0008-000000000008', 'REG 21-3', 'Évaluation de l''impact sécurité des changements', 'Il faut apprécier les incidences potentielles de ces changements sur la sécurité de l''information.', 'Mapping ISO 27001 : A.8.32', 11),
('00000000-0000-0000-0008-000000000008', 'REG 21-4', 'Procédure formelle d''autorisation des changements', 'Une procédure d''autorisation formelle des changements proposés doit être mise en œuvre.', 'Mapping ISO 27001 : A.8.32', 12),
('00000000-0000-0000-0008-000000000008', 'REG 21-5', 'Vérification du respect des exigences de sécurité', 'Il faut vérifier que les exigences de sécurité de l''information sont respectées.', 'Mapping ISO 27001 : A.8.32', 13),
('00000000-0000-0000-0008-000000000008', 'REG 21-6', 'Communication des changements aux personnes concernées', 'Il faut transmettre les informations détaillées sur les changements apportés à toutes les personnes concernées.', 'Mapping ISO 27001 : A.8.32', 14),
('00000000-0000-0000-0008-000000000008', 'REG 21-7', 'Procédures de repli en cas d''échec', 'Il faut mettre en œuvre les procédures de repli, incluant les procédures et les responsabilités en cas d''abandon et de récupération, suite à l''échec des changements ou à des événements imprévus.', 'Mapping ISO 27001 : A.8.32', 15),
('00000000-0000-0000-0008-000000000008', 'REG 21-8', 'Processus de modification d''urgence', 'Il faut mettre en place un processus de modification d''urgence permettant une mise en œuvre rapide et contrôlée des modifications requises par la résolution d''un incident.', 'Mapping ISO 27001 : A.8.32', 16),

-- Obj. 22 : Séparation des environnements
('00000000-0000-0000-0008-000000000008', 'REG 22-1', 'Environnements distincts (dev, test, exploitation)', 'Il faut exécuter les logiciels de développement et les logiciels d''exploitation sur des systèmes informatiques différents et dans des domaines ou des répertoires différents.', 'Mapping ISO 27001 : A.8.31', 17),
('00000000-0000-0000-0008-000000000008', 'REG 22-2', 'Tests en environnement de test avant production', 'Il faut tester les modifications à apporter aux systèmes et aux applications dans un environnement de test avant de les appliquer aux systèmes en exploitation.', 'Mapping ISO 27001 : A.8.29, A.8.31', 18),
('00000000-0000-0000-0008-000000000008', 'REG 22-3', 'Séparation des activités de développement et de test', 'Les activités de développement doivent être séparées des activités de test.', 'Mapping ISO 27001 : A.8.31', 19),
('00000000-0000-0000-0008-000000000008', 'REG 22-4', 'Outils de développement non accessibles depuis les systèmes en exploitation', 'Les compilateurs, les éditeurs et les autres outils de développement ou les utilitaires systèmes ne doivent pas être accessibles depuis les systèmes en exploitation, lorsqu''ils ne sont pas nécessaires.', 'Mapping ISO 27001 : A.8.31', 20),
('00000000-0000-0000-0008-000000000008', 'REG 22-5', 'Profils différents pour exploitation et test', 'Les utilisateurs doivent utiliser des profils différents pour les systèmes en exploitation et les systèmes de test, et les menus doivent afficher les messages d''identification adéquats pour réduire le risque d''erreur.', 'Mapping ISO 27001 : A.8.31', 21),
('00000000-0000-0000-0008-000000000008', 'REG 22-6', 'Interdiction de copier des données sensibles en test', 'Il ne faut pas copier de données sensibles dans l''environnement du système de test, à moins qu''il ne soit doté de mesures de sécurité équivalentes.', 'Mapping ISO 27001 : A.8.33', 22),

-- Obj. 23 : Protection contre les logiciels malveillants
('00000000-0000-0000-0008-000000000008', 'REG 23-1', 'Antivirus installé sur tous les postes et terminaux', 'Un outil de protection contre les logiciels malveillants doit être installé sur tous les serveurs, les ordinateurs fixes et les terminaux mobiles.', 'Mapping ISO 27001 : A.8.7', 23),
('00000000-0000-0000-0008-000000000008', 'REG 23-2', 'Mise à jour régulière des outils de protection', 'L''utilisateur, ou à défaut, l''administrateur doit prendre toutes les mesures et effectuer les paramétrages nécessaires pour la mise à jour de l''outil de protection.', 'Mapping ISO 27001 : A.8.7', 24),
('00000000-0000-0000-0008-000000000008', 'REG 23-3', 'Logiciels de détection et réparation à jour', 'Il faut installer et mettre à jour régulièrement les logiciels de détection et de réparation pour analyser les ordinateurs et les supports.', 'Mapping ISO 27001 : A.8.7', 25),
('00000000-0000-0000-0008-000000000008', 'REG 23-4', 'Alerte diffusée en cas de détection de malware', 'En cas de détection de logiciels malveillants, une alerte doit être diffusée dans l''ensemble de l''entité.', 'Mapping ISO 27001 : A.8.7', 26),
('00000000-0000-0000-0008-000000000008', 'REG 23-5', 'Ne pas ouvrir les courriers électroniques suspects', 'Les courriers électroniques suspects, avec ou sans pièces jointes, ne doivent pas être ouverts.', 'Mapping ISO 27001 : A.8.7', 27),
('00000000-0000-0000-0008-000000000008', 'REG 23-6', 'Anti-spams et listes noires sur les serveurs de messagerie', 'Des anti-spams doivent être installés sur les serveurs de messagerie. Des listes noires en temps réel doivent être utilisées pour bloquer les spams.', 'Mapping ISO 27001 : A.8.7, A.8.23', 28),
('00000000-0000-0000-0008-000000000008', 'REG 23-7', 'Filtres de contenu web installés', 'Des filtres de contenus doivent être installés pour empêcher l''utilisation de sites web malveillants ou suspectés en tant que tels.', 'Mapping ISO 27001 : A.8.23', 29),
('00000000-0000-0000-0008-000000000008', 'REG 23-8', 'Procédures de continuité post-attaque', 'Établir des procédures de continuité d''activités de l''organisme, après une attaque par logiciels malveillants, comprenant les sauvegardes de tous les logiciels et données nécessaires ainsi que les dispositions de sauvegarde.', 'Mapping ISO 27001 : A.5.29, A.8.7', 30),
('00000000-0000-0000-0008-000000000008', 'REG 23-9', 'Vigilance lors de la maintenance et du dépannage', 'Les utilisateurs doivent veiller à se protéger de l''introduction de logiciels malveillants qui peuvent contourner les mesures de protection habituelles, lors des opérations de maintenance et de dépannage.', 'Mapping ISO 27001 : A.8.7', 31),
('00000000-0000-0000-0008-000000000008', 'REG 23-10', 'Bulletins d''alerte vérifiés de sources qualifiées', 'Il faut s''assurer que les bulletins d''alerte concernant les logiciels malveillants sont exacts et informatifs, et proviennent de sources qualifiées et réputées (publications réputées, sites internet fiables, éditeurs de logiciels contre les logiciels malveillants).', 'Mapping ISO 27001 : A.5.7, A.8.7', 32),

-- Obj. 24 : Sauvegarde
('00000000-0000-0000-0008-000000000008', 'REG 24-1', 'Sauvegarde périodique des données et configurations', 'Les données des utilisateurs, les configurations, les fichiers système et les messages électroniques doivent être périodiquement sauvegardés dans des serveurs dédiés, sur site et/ou hors site ou dans des supports de stockage amovibles.', 'Fréquence : incrémentielle quotidienne (données sensibles), complète hebdomadaire (données non sensibles), complète hebdomadaire (système et réseau). Mapping ISO 27001 : A.8.13', 33),
('00000000-0000-0000-0008-000000000008', 'REG 24-3', 'Interdiction du stockage en ligne gratuit', 'Le stockage en ligne gratuit, offert par certains prestataires privés, doit être interdit.', 'Mapping ISO 27001 : A.5.23, A.8.13', 34),
('00000000-0000-0000-0008-000000000008', 'REG 24-4', 'Chiffrement des sauvegardes sensibles', 'Il faut protéger les données sensibles sauvegardées en les chiffrant avec des moyens de chiffrement labellisés par la Commission nationale de cryptologie.', 'Mapping ISO 27001 : A.8.13, A.8.24', 35),
('00000000-0000-0000-0008-000000000008', 'REG 24-5', 'Sécurisation des locaux de stockage des sauvegardes', 'Les locaux de stockage des données sensibles doivent être sécurisés.', 'Mapping ISO 27001 : A.7.3, A.8.13', 36),
('00000000-0000-0000-0008-000000000008', 'REG 24-7', 'Test périodique de restauration des sauvegardes', 'Un test de restauration doit être effectué périodiquement pour vérifier l''intégrité des données sauvegardées. La fréquence de ces tests doit être proportionnelle au degré de sensibilité des systèmes.', 'Mapping ISO 27001 : A.8.13', 37),

-- Obj. 25 : Journalisation et surveillance
('00000000-0000-0000-0008-000000000008', 'REG 25-1', 'Journaux d''événements complets', 'Les journaux d''événements doivent contenir : identifiants des utilisateurs, activités du système, date/heure des événements significatifs, identité ou emplacement du terminal, enregistrements des tentatives d''accès, modifications de configuration, utilisation des privilèges.', 'Mapping ISO 27001 : A.8.15', 38),
('00000000-0000-0000-0008-000000000008', 'REG 25-2', 'Protection des journaux contre la falsification', 'Les moyens de journalisation et l''information journalisée doivent être protégés contre les risques de falsification et les risques d''accès non autorisés.', 'Mapping ISO 27001 : A.8.15', 39),
('00000000-0000-0000-0008-000000000008', 'REG 25-3', 'Analyse automatique des journaux', 'Les fichiers de journalisation doivent être analysés par des outils automatiques destinés à cet effet.', 'Mapping ISO 27001 : A.8.15, A.8.16', 40),
('00000000-0000-0000-0008-000000000008', 'REG 25-4', 'Journalisation des activités administrateurs', 'Il faut journaliser les activités de l''administrateur système et les activités de l''opérateur système, protéger et revoir régulièrement les journaux.', 'Mapping ISO 27001 : A.8.15', 41),
('00000000-0000-0000-0008-000000000008', 'REG 25-5', 'Système de détection des intrusions (IDS)', 'Un système de détection des intrusions hors du contrôle des administrateurs système et réseau doit être utilisé pour vérifier la conformité des activités d''administration système et réseau.', 'Mapping ISO 27001 : A.8.16', 42),
('00000000-0000-0000-0008-000000000008', 'REG 25-6', 'Vérification permanente des journaux', 'Les journaux doivent être vérifiés de façon permanente.', 'Mapping ISO 27001 : A.8.15', 43),
('00000000-0000-0000-0008-000000000008', 'REG 25-7', 'Journalisation de tous les événements majeurs', 'Tous les événements majeurs doivent être enregistrés sur n''importe quel ordinateur ou système manipulant des données sensibles.', 'Mapping ISO 27001 : A.8.15', 44),

-- Obj. 26 : Synchronisation des horloges
('00000000-0000-0000-0008-000000000008', 'REG 26-1', 'Synchronisation NTP centralisée', 'Toutes les horloges système, les horloges des ordinateurs et des périphériques réseau doivent être synchronisées à un serveur de temps central.', 'Mapping ISO 27001 : A.8.17', 45),
('00000000-0000-0000-0008-000000000008', 'REG 26-2', 'Serveur de temps de secours', 'Le serveur de temps doit être doublé d''un serveur de secours installé dans un endroit sécurisé.', 'Mapping ISO 27001 : A.8.17', 46),
('00000000-0000-0000-0008-000000000008', 'REG 26-3', 'Interdiction de modifier l''heure par les utilisateurs', 'Les utilisateurs ne doivent pas être en mesure de changer la date, les paramètres du fuseau horaire ainsi que les paramètres de synchronisation du temps ou de l''horloge du système.', 'Mapping ISO 27001 : A.8.17', 47),

-- Obj. 27 : Installation de logiciels sur les systèmes en exploitation
('00000000-0000-0000-0008-000000000008', 'REG 27-1', 'Mise à jour par administrateurs qualifiés après autorisation', 'La mise à jour des logiciels en exploitation, des applications et des programmes doit être effectuée par des administrateurs qualifiés après autorisation du responsable de l''entité ou de l''AQSSI.', 'Mapping ISO 27001 : A.8.19', 48),
('00000000-0000-0000-0008-000000000008', 'REG 27-2', 'Correctifs recommandés par les éditeurs', 'Les correctifs doivent être recommandés par les administrateurs système ou par les éditeurs du logiciel.', 'Mapping ISO 27001 : A.8.8', 49),
('00000000-0000-0000-0008-000000000008', 'REG 27-3', 'Test des correctifs avant mise en production', 'Les correctifs doivent être appliqués sur un site de test, et si aucune anomalie n''est constatée, ils sont appliqués sur le site de production. Les correctifs critiques doivent avoir une haute priorité et être immédiatement installés.', 'Mapping ISO 27001 : A.8.8, A.8.29', 50),
('00000000-0000-0000-0008-000000000008', 'REG 27-5', 'Sauvegarde complète avant l''application d''un correctif', 'Une sauvegarde complète doit être effectuée avant l''application d''un correctif.', 'Mapping ISO 27001 : A.8.8, A.8.13', 51),
('00000000-0000-0000-0008-000000000008', 'REG 27-7', 'Téléchargement automatique des mises à jour recommandées', 'Les ordinateurs connectés à internet doivent être configurés pour télécharger automatiquement les mises à jour recommandées. Les ordinateurs non connectés doivent être mis à jour manuellement.', 'Mapping ISO 27001 : A.8.8', 52),
('00000000-0000-0000-0008-000000000008', 'REG 27-8', 'Journalisation des mises à jour et correctifs', 'Les mises à jour, mises à niveau et correctifs doivent être journalisés par l''administrateur système dans un registre.', 'Mapping ISO 27001 : A.8.8, A.8.15', 53),
('00000000-0000-0000-0008-000000000008', 'REG 27-9', 'Restauration en cas d''impact négatif', 'Si l''application automatique d''un correctif ou d''une mise à jour affecte négativement les systèmes, il faut rétablir les systèmes originaux à partir des sauvegardes.', 'Mapping ISO 27001 : A.8.8, A.8.13', 54);

-- ============================================================
-- CLM — Cloud, appareils mobiles et télétravail (10 contrôles)
-- Chapitre IX — Objectif 28
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000009', 'REG 28-1', 'Externalisation basée sur une analyse de risques', 'Toute opération d''externalisation s''appuie sur une analyse de risques préalable, de façon à formaliser des objectifs de sécurité et définir des mesures adaptées. L''ensemble des objectifs de sécurité ainsi formalisés permet de définir une cible de sécurité servant de cadre au contrat établi avec le prestataire.', 'Mapping ISO 27001 : A.5.21, A.5.23', 1),
('00000000-0000-0000-0008-000000000009', 'REG 28-2', 'Hébergement national obligatoire des données sensibles', 'L''hébergement des données sensibles de l''Administration sur le territoire national est obligatoire, sauf accord du HFD, et dérogation dûment motivée et précisée dans la décision d''homologation.', 'Principe de souveraineté numérique. Mapping ISO 27001 : A.5.23', 2),
('00000000-0000-0000-0008-000000000009', 'REG 28-3', 'Sensibilisation aux risques du télétravail et des terminaux mobiles', 'Sensibiliser les utilisateurs aux problèmes liés à la sécurité des systèmes d''information, notamment les risques encourus dans le cadre du télétravail et de l''utilisation des terminaux mobiles dans les lieux publics, les aéroports, les chambres d''hôtel, les salles de congrès, de réunions, de conférences et dans d''autres zones non sécurisées.', 'Mapping ISO 27001 : A.6.7, A.8.1', 3),
('00000000-0000-0000-0008-000000000009', 'REG 28-4', 'Protection physique des appareils mobiles contre le vol', 'Les appareils mobiles doivent être physiquement protégés contre le vol, en cas de déplacement des utilisateurs. Ils doivent être mis sous clé et dotés de systèmes de verrouillage spéciaux.', 'Mapping ISO 27001 : A.8.1', 4),
('00000000-0000-0000-0008-000000000009', 'REG 28-5', 'Politique de contrôle d''accès mobile et protection anti-malware', 'Mettre en place une politique de contrôle d''accès, protéger les appareils mobiles contre les logiciels malveillants, effectuer des sauvegardes et éviter l''installation d''applications non approuvées.', 'Mapping ISO 27001 : A.8.1, A.8.7', 5),
('00000000-0000-0000-0008-000000000009', 'REG 28-6', 'Chiffrement labellisé pour les données mobiles', 'Empêcher la compromission et la divulgation des informations sensibles stockées et traitées par les appareils mobiles en utilisant les algorithmes de chiffrement labellisés par la Commission nationale de cryptologie.', 'Mapping ISO 27001 : A.8.1, A.8.24', 6),
('00000000-0000-0000-0008-000000000009', 'REG 28-7', 'Usage professionnel exclusif des appareils mobiles', 'Veiller à ce que les appareils mobiles de l''organisme ne soient utilisés que pour des usages professionnels.', 'Mapping ISO 27001 : A.8.1', 7),
('00000000-0000-0000-0008-000000000009', 'REG 28-8', 'Ne pas se connecter via des réseaux sans fil non sécurisés', 'Éviter de se connecter au réseau de l''organisme par l''intermédiaire de réseaux sans fil non sécurisés.', 'Mapping ISO 27001 : A.8.1, A.8.20', 8),
('00000000-0000-0000-0008-000000000009', 'REG 28-9', 'Mécanisme d''effacement à distance en cas de perte', 'Mettre en place un mécanisme d''effacement des données, en cas de perte d''appareils mobiles.', 'Mapping ISO 27001 : A.8.1, A.8.10', 9),
('00000000-0000-0000-0008-000000000009', 'REG 28-10', 'Contrôle des appareils mobiles tout au long de leur cycle de vie', 'Procéder au contrôle des appareils mobiles durant tout leur cycle de vie.', 'Mapping ISO 27001 : A.8.1', 10);

-- ============================================================
-- INC — Gestion des incidents (11 contrôles)
-- Chapitre X — Objectif 29
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000010', 'REG 29-1', 'Procédures de surveillance, détection, analyse et signalement', 'Mettre en œuvre des procédures de surveillance, de détection, d''analyse et de signalement des événements et des incidents concernant les activités des réseaux.', 'Mapping ISO 27001 : A.5.24, A.5.25', 1),
('00000000-0000-0000-0008-000000000010', 'REG 29-2', 'Structure d''alerte et de réaction rapide avec point focal', 'Mettre en place, au sein de l''entité, une structure d''alerte et de réaction rapide à tout incident relatif à la sécurité des systèmes d''information, composée d''un personnel qualifié avec un point focal qui sert d''interlocuteur entre l''entité et les autres centres de gestion des incidents.', 'Organismes compétents : ADIE, STCC-SSI, ARTP. Mapping ISO 27001 : A.5.24', 2),
('00000000-0000-0000-0008-000000000010', 'REG 29-3', 'Remontée rapide et coordination des incidents', 'Les structures d''alerte et de réaction rapide doivent remonter tout incident lié à la sécurité des systèmes d''information de l''entité et les signaler aux organismes compétents (ADIE, STCC-SSI, ARTP…). Les actions à mener doivent être coordonnées.', 'Mapping ISO 27001 : A.5.24, A.5.26', 3),
('00000000-0000-0000-0008-000000000010', 'REG 29-4', 'Système de redondance pour garantir la disponibilité', 'Un système de redondance des moyens de traitement de l''information doit être mis en place en vue d''en garantir la disponibilité.', 'Mapping ISO 27001 : A.8.14', 4),
('00000000-0000-0000-0008-000000000010', 'REG 29-5', 'Revue périodique du plan de continuité d''activité', 'Il faut revoir régulièrement le plan de continuité d''activités pour prendre en compte les changements intervenus dans le système d''information afin d''en maintenir la validité et l''efficacité.', 'Mapping ISO 27001 : A.5.29, A.5.30', 5),
('00000000-0000-0000-0008-000000000010', 'REG 29-6', 'Test périodique du plan de continuité', 'Il faut tester périodiquement le plan afin de s''assurer de sa fiabilité.', 'Mapping ISO 27001 : A.5.29', 6),
('00000000-0000-0000-0008-000000000010', 'REG 29-7', 'Formation des utilisateurs aux actions en cas de violation', 'Les utilisateurs doivent être formés sur les actions à mener en cas de violation de la politique de sécurité.', 'Mapping ISO 27001 : A.6.3, A.5.24', 7),
('00000000-0000-0000-0008-000000000010', 'REG 29-8', 'Formation à la détection des actions suspectes', 'Les utilisateurs doivent être formés à la détection des actions suspectes ou anormales pouvant présager un incident lié à la sécurité des systèmes d''information (dysfonctionnements ou comportements anormaux du système d''information).', 'Mapping ISO 27001 : A.5.24, A.6.3', 8),
('00000000-0000-0000-0008-000000000010', 'REG 29-9', 'Procédure de réponse aux incidents documentée', 'La procédure de réponse aux incidents doit comprendre : une phase de recueil et d''analyse des preuves, une communication détaillée sur l''incident survenu, la méthode de traitement utilisée, etc.', 'Mapping ISO 27001 : A.5.25, A.5.26, A.5.28', 9),
('00000000-0000-0000-0008-000000000010', 'REG 29-10', 'Procédure de recueil des preuves numériques', 'La procédure relative au recueil de preuves doit prendre en compte la chaîne de traçabilité, les aptitudes et la sécurité du personnel, les fonctions et les responsabilités, la documentation et les séances d''information. Il faut appliquer la norme ISO/CEI 27037.', 'Référence : ISO/CEI 27037. Mapping ISO 27001 : A.5.28', 10),
('00000000-0000-0000-0008-000000000010', 'REG 29-11', 'Typologie des incidents et retours d''expérience', 'Il faut déterminer la typologie des incidents de sécurité, et en tirer tous les enseignements nécessaires.', 'Mapping ISO 27001 : A.5.27', 11);

-- ============================================================
-- AUD — Audit et conformité (7 contrôles)
-- Chapitre XI — Objectif 30
-- ============================================================

insert into public.controls (domain_id, code, name, description, guidance, sort_order) values
('00000000-0000-0000-0008-000000000011', 'REG 30-1', 'Audits SSI réguliers pour vérifier l''atteinte des objectifs', 'Il faut effectuer des audits pour s''assurer que les objectifs de sécurité sont atteints et que les politiques de sécurité sont conformes aux normes de sécurité en vigueur. Les rapports d''audit doivent être communiqués à la Commission nationale de cryptologie.', 'Mapping ISO 27001 : A.5.35, A.5.36', 1),
('00000000-0000-0000-0008-000000000011', 'REG 30-2', 'Compétence des auditeurs SSI', 'Les auditeurs des systèmes d''information de l''entité doivent être compétents.', 'Mapping ISO 27001 : A.5.35', 2),
('00000000-0000-0000-0008-000000000011', 'REG 30-3', 'Rapports d''audit avec recommandations au HFD et à la Commission', 'Les auditeurs doivent établir des rapports d''audit à l''attention notamment du Haut Fonctionnaire de Défense (HFD) accompagnés de recommandations à mettre en œuvre pour corriger les éventuelles anomalies. En cas de violation flagrante des procédures, des sanctions doivent être prises conformément aux textes en vigueur. Les rapports d''audit doivent être communiqués à la Commission nationale de cryptologie qui fera un rapport de synthèse à l''attention du Président de la République.', 'Chaîne de reporting : Auditeur → HFD → Commission nationale de cryptologie → Président de la République.', 3),
('00000000-0000-0000-0008-000000000011', 'REG 30-4', 'Application des mesures de conformité proposées', 'Toutes les structures auditées doivent appliquer les mesures proposées et faire leurs rapports de conformité.', 'Mapping ISO 27001 : A.5.36', 4),
('00000000-0000-0000-0008-000000000011', 'REG 30-5', 'Conformité légale et réglementaire', 'Il faut se conformer aux lois et règlements concernant l''utilisation, l''importation, l''exportation et la fourniture des moyens et des prestations de cryptologie, les droits de propriété intellectuelle, la protection de la vie privée et des données à caractère personnel, et, partant, la cybersécurité.', 'Référence : Loi 2008-41 (cryptologie), Loi 2008-12 (données personnelles). Mapping ISO 27001 : A.5.31, A.5.32, A.5.34', 5),
('00000000-0000-0000-0008-000000000011', 'REG 30-6', 'Publication et mise à jour des normes de sécurité par la Commission', 'La Commission nationale de cryptologie publie et met à jour régulièrement les normes de sécurité auxquelles doivent se conformer tous les systèmes d''information de l''État du Sénégal.', 'Mapping ISO 27001 : A.5.31', 6),
('00000000-0000-0000-0008-000000000011', 'REG 30-7', 'Rapports complets communiqués aux autorités', 'Des rapports complets doivent être communiqués aux autorités compétentes des entités de telle sorte que des mesures puissent être prises lors de la planification de futurs projets sur la base de l''expérience actuelle.', 'Mapping ISO 27001 : A.5.36', 7);
